import { GoogleGenAI, Type, Schema } from "@google/genai";
import { TranscriptionResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const TRANSCRIPTION_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    raw: {
      type: Type.STRING,
      description: "De letterlijke transcriptie inclusief timestamps [MM:SS] en spreker labels.",
    },
    cleaned: {
      type: Type.STRING,
      description: "Een professioneel opgeschoonde versie zonder stopwoorden en haperingen.",
    },
    summary: {
      type: Type.STRING,
      description: "Een gestructureerde samenvatting met actiepunten.",
    }
  },
  required: ["raw", "cleaned", "summary"],
};

function cleanJsonString(jsonString: string): string {
  let cleaned = jsonString.trim();
  // Remove markdown code blocks if the model included them despite the mimeType setting
  if (cleaned.startsWith("```")) {
    cleaned = cleaned.replace(/^```(?:json)?\n?/, "").replace(/\n?```$/, "");
  }
  return cleaned.trim();
}

export const transcribeAudio = async (
  input: { base64?: string; mimeType?: string; text?: string }
): Promise<TranscriptionResult> => {
  try {
    const modelId = "gemini-3-flash-preview";

    const systemInstruction = `
    Je bent de HB∞ Transcribe Assistant.
    Doel: Transcribeer of verwerk audio/tekst snel en gestructureerd.

    Regels:
    1. Herken sprekerwissels.
    2. Gebruik timestamps [MM:SS] waar mogelijk.
    3. Detecteer automatisch de taal.
    4. Als de input tekst is (van een live sessie), maak er een formele 'raw' transcriptie van, een 'cleaned' versie en een 'summary'.
    5. Belangrijk: Houd de 'raw' transcriptie compact als de brontekst zeer lang is om JSON-limieten niet te overschrijden.

    Retourneer ALTIJD een strikt JSON object volgens het schema.
    `;

    const contents = input.text 
      ? { parts: [{ text: `Verwerk de volgende live getranscribeerde tekst naar een gestructureerd verslag: ${input.text}` }] }
      : { 
          parts: [
            { inlineData: { mimeType: input.mimeType || 'audio/mp3', data: input.base64 || '' } },
            { text: "Transcribeer en analyseer dit audiobestand." }
          ]
        };

    const response = await ai.models.generateContent({
      model: modelId,
      contents,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: TRANSCRIPTION_SCHEMA,
        temperature: 0.1,
      },
    });

    const text = response.text;
    if (!text) throw new Error("Geen antwoord ontvangen van Gemini.");

    const cleanedText = cleanJsonString(text);
    return JSON.parse(cleanedText) as TranscriptionResult;

  } catch (error) {
    console.error("Transcription error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { Mic, StopCircle, Radio, Sparkles, AlertCircle } from 'lucide-react';

interface LiveTranscribeProps {
  onFinalize: (fullText: string) => void;
  disabled: boolean;
}

export const LiveTranscribe: React.FC<LiveTranscribeProps> = ({ onFinalize, disabled }) => {
  const [isActive, setIsActive] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [error, setError] = useState<string | null>(null);

  const sessionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const accumulatedTextRef = useRef('');

  const encode = (bytes: Uint8Array) => {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
    return btoa(binary);
  };

  const createBlob = (data: Float32Array) => {
    const int16 = new Int16Array(data.length);
    for (let i = 0; i < data.length; i++) int16[i] = data[i] * 32768;
    return {
      data: encode(new Uint8Array(int16.buffer)),
      mimeType: 'audio/pcm;rate=16000',
    };
  };

  const startLiveSession = async () => {
    setError(null);
    setTranscript('');
    accumulatedTextRef.current = '';

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextRef.current = audioCtx;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            const source = audioCtx.createMediaStreamSource(stream);
            const processor = audioCtx.createScriptProcessor(4096, 1, 1);

            processor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createBlob(inputData);
              sessionPromise.then(session => session.sendRealtimeInput({ media: pcmBlob }));
            };

            source.connect(processor);
            processor.connect(audioCtx.destination);
            (window as any)._liveProcessor = processor; // Keep reference to avoid GC
            (window as any)._liveStream = stream;
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.inputTranscription) {
              const newText = message.serverContent.inputTranscription.text;
              accumulatedTextRef.current += newText;
              setTranscript(prev => prev + newText);
            }
          },
          onerror: (e) => {
            console.error("Live API Error:", e);
            setError("Verbinding met Live API verbroken.");
          },
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          systemInstruction: "Je luistert naar een gebruiker en transcribeert de tekst live. Reageer zelf niet met audio, luister alleen en transcribeer.",
        },
      });

      sessionRef.current = await sessionPromise;
      setIsActive(true);

    } catch (err) {
      console.error("Failed to start live session:", err);
      setError("Kon microfoon niet activeren of verbinden met de server.");
    }
  };

  const stopLiveSession = () => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
    }
    const stream = (window as any)._liveStream as MediaStream;
    if (stream) stream.getTracks().forEach(t => t.stop());

    setIsActive(false);
    if (accumulatedTextRef.current.trim()) {
      onFinalize(accumulatedTextRef.current);
    }
  };

  return (
    <div className="w-full max-w-2xl mx-auto mb-8">
      <div className={`relative flex flex-col w-full min-h-[16rem] border-2 border-dashed rounded-xl transition-all duration-300 overflow-hidden ${
        isActive ? "border-blue-400 bg-slate-900" : "border-slate-300 bg-white"
      }`}>

        {!isActive ? (
          <div className="flex flex-col items-center justify-center flex-grow p-8 space-y-4">
            <button
              onClick={startLiveSession}
              disabled={disabled}
              className="p-6 rounded-full bg-blue-600 text-white hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all hover:scale-105 active:scale-95 disabled:opacity-50"
            >
              <Radio className="w-8 h-8 animate-pulse" />
            </button>
            <div className="text-center">
              <p className="text-lg font-semibold text-slate-700">Start Live Sessie</p>
              <p className="text-sm text-slate-500">Spraak wordt direct omgezet in tekst op het scherm.</p>
            </div>
          </div>
        ) : (
          <div className="flex flex-col h-full p-6 animate-in fade-in duration-500">
            <div className="flex justify-between items-center mb-4">
              <div className="flex items-center gap-2 text-blue-400 text-xs font-bold uppercase tracking-widest">
                <span className="w-2 h-2 rounded-full bg-red-500 animate-ping"></span>
                Live Transcribing
              </div>
              <button
                onClick={stopLiveSession}
                className="flex items-center gap-2 px-4 py-2 bg-white/10 hover:bg-white/20 text-white rounded-lg text-sm font-medium transition-colors"
              >
                <Sparkles className="w-4 h-4 text-blue-300" />
                Stop & Analyseer
              </button>
            </div>

            <div className="flex-grow bg-white/5 rounded-lg p-4 font-mono text-blue-100/90 leading-relaxed overflow-y-auto max-h-48 custom-scrollbar">
              {transcript || <span className="text-blue-100/30">Begin met praten...</span>}
            </div>

            <div className="mt-4 flex justify-center gap-1 h-6">
              {[...Array(12)].map((_, i) => (
                <div 
                  key={i} 
                  className="w-1 bg-blue-500/50 rounded-full animate-bounce" 
                  style={{ 
                    height: `${Math.random() * 100}%`, 
                    animationDuration: `${0.5 + Math.random()}s`,
                    animationDelay: `${i * 0.05}s`
                  }} 
                />
              ))}
            </div>
          </div>
        )}
      </div>

      {error && (
        <div className="mt-4 p-4 bg-red-50 border border-red-200 rounded-lg flex items-start gap-3 text-red-700">
          <AlertCircle className="w-5 h-5 flex-shrink-0 mt-0.5" />
          <p className="text-sm">{error}</p>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { FileUpload } from './components/FileUpload';
import { AudioRecorder } from './components/AudioRecorder';
import { LiveTranscribe } from './components/LiveTranscribe';
import { ResultDisplay } from './components/ResultDisplay';
import { ProcessingState } from './components/ProcessingState';
import { FileData, ProcessingStatus, TranscriptionResult } from './types';
import { transcribeAudio } from './services/geminiService';
import { Infinity, Mic, ChevronLeft, Upload, Disc, Radio } from 'lucide-react';

const App: React.FC = () => {
  const [status, setStatus] = useState<ProcessingStatus>(ProcessingStatus.IDLE);
  const [transcription, setTranscription] = useState<TranscriptionResult | null>(null);
  const [currentFile, setCurrentFile] = useState<FileData | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [inputMode, setInputMode] = useState<'upload' | 'record' | 'live'>('upload');

  const handleAudioProcessing = async (data: FileData | string) => {
    setStatus(ProcessingStatus.TRANSCRIBING);
    setError(null);
    setTranscription(null);

    try {
      let result;
      if (typeof data === 'string') {
        // From Live Transcribe
        setCurrentFile({ name: 'Live Sessie', size: 0, type: 'text/plain', base64: '' });
        result = await transcribeAudio({ text: data });
      } else {
        // From Upload or Batch Record
        setCurrentFile(data);
        result = await transcribeAudio({ base64: data.base64, mimeType: data.type });
      }

      setTranscription(result);
      setStatus(ProcessingStatus.COMPLETED);
    } catch (err: any) {
      console.error(err);
      setError("Er is een fout opgetreden bij het verwerken. Dit kan komen door een te lange opname of een ongeldige JSON-respons. Probeer het opnieuw.");
      setStatus(ProcessingStatus.ERROR);
    }
  };

  const handleReset = () => {
    setStatus(ProcessingStatus.IDLE);
    setTranscription(null);
    setCurrentFile(null);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-10">
        <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={handleReset}>
            <div className="bg-slate-900 text-white p-1.5 rounded-md">
              <Infinity className="w-5 h-5" />
            </div>
            <h1 className="text-xl font-bold text-slate-900 tracking-tight">
              HB∞ <span className="font-normal text-slate-600">Transcribe Assistant</span>
            </h1>
          </div>
          <div className="hidden md:flex items-center gap-4 text-sm text-slate-500">
             <span className="flex items-center gap-1">
               <Mic className="w-4 h-4 text-blue-500" />
               Auto-detectie Taal
             </span>
             <span className="bg-blue-50 text-blue-700 px-2 py-0.5 rounded text-xs font-semibold tracking-wider">PREMIUM</span>
          </div>
        </div>
      </header>

      <main className="flex-grow flex flex-col items-center justify-start pt-12 px-4 pb-12">

        {status === ProcessingStatus.IDLE && (
          <div className="w-full max-w-2xl text-center mb-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <h2 className="text-3xl sm:text-4xl font-bold text-slate-800 mb-4">
              Zet spraak om in heldere tekst
            </h2>
            <p className="text-lg text-slate-600 mb-8">
              Kies voor een bestaand bestand, een snelle opname of een live sessie met direct resultaat.
            </p>

            <div className="inline-flex bg-slate-200 p-1 rounded-xl mb-12 shadow-inner">
              <button
                onClick={() => setInputMode('upload')}
                className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-medium transition-all duration-200 ${
                  inputMode === 'upload' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                <Upload className="w-4 h-4" />
                Bestand
              </button>
              <button
                onClick={() => setInputMode('record')}
                className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-medium transition-all duration-200 ${
                  inputMode === 'record' ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                <Disc className="w-4 h-4" />
                Opname
              </button>
              <button
                onClick={() => setInputMode('live')}
                className={`flex items-center gap-2 px-5 py-2.5 rounded-lg text-sm font-medium transition-all duration-200 ${
                  inputMode === 'live' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                <Radio className="w-4 h-4" />
                Live Transcribe
              </button>
            </div>

            <div className="transition-all duration-300">
              {inputMode === 'upload' && <FileUpload onFileSelect={handleAudioProcessing} disabled={false} />}
              {inputMode === 'record' && <AudioRecorder onRecordingComplete={handleAudioProcessing} disabled={false} />}
              {inputMode === 'live' && <LiveTranscribe onFinalize={handleAudioProcessing} disabled={false} />}
            </div>
          </div>
        )}

        <ProcessingState status={status} />

        {status === ProcessingStatus.ERROR && (
          <div className="w-full max-w-2xl text-center">
            <div className="bg-red-50 border border-red-200 rounded-xl p-8 text-red-800 mb-6 shadow-sm">
              <p className="font-bold text-lg mb-2">Verwerking mislukt</p>
              <p className="text-sm opacity-90">{error}</p>
            </div>
            <button 
              onClick={handleReset}
              className="px-6 py-2 bg-slate-900 text-white rounded-lg font-medium hover:bg-slate-800 transition-colors flex items-center justify-center gap-2 mx-auto"
            >
              <ChevronLeft className="w-4 h-4" /> Probeer opnieuw
            </button>
          </div>
        )}

        {status === ProcessingStatus.COMPLETED && transcription && (
          <div className="w-full flex flex-col items-center gap-6 animate-in fade-in slide-in-from-bottom-8 duration-700">
            <div className="w-full max-w-4xl flex justify-between items-end mb-2">
              <div>
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-green-500"></span>
                  {currentFile?.name}
                </h3>
                <p className="text-sm text-slate-500">Transcriptie succesvol gegenereerd</p>
              </div>
              <button 
                onClick={handleReset}
                className="text-blue-600 hover:text-blue-700 text-sm font-bold transition-colors bg-blue-50 px-4 py-2 rounded-lg"
              >
                Nieuwe sessie
              </button>
            </div>
            <ResultDisplay result={transcription} />
          </div>
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 py-8 mt-auto">
        <div className="max-w-6xl mx-auto px-4 text-center">
          <div className="flex justify-center items-center gap-2 mb-2 text-slate-900 font-bold">
             <Infinity className="w-5 h-5" /> HB∞
          </div>
          <p className="text-slate-400 text-sm">© {new Date().getFullYear()} HB∞ Transcribe Assistant. High-end AI Transcription.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;
